from enum import Enum

class Status(Enum):
    PENDING = 1
    ACTIVE = 2
    INACTIVE = 3

# 使用
def process(status: Status):
    if status == Status.ACTIVE:
        print("Active")
    elif status == Status.PENDING:
        print("Pending")
    else:
        print("Inactive")

process(Status.PENDING)
